module RefModule (
    input [3:0] a,
    input [3:0] b,
    output reg [7:0] product
);

    integer obf_i;

    always @(*) begin
        product = 8'b00000000;
        for (obf_i = 0; obf_i < 4; obf_i = obf_i + 1) begin
            if (b[obf_i])
                product = product + (a << obf_i);
        end
    end

endmodule
